import anthropic
from typing import Any

client = anthropic.Anthropic()

def run_agent(
    system: str,
    tools: list[dict],
    dispatch: dict[str, Any],  # name -> callable
    task: str,
    max_turns: int = 20,
) -> str:
    messages: list[dict] = [{"role": "user", "content": task}]

    for _ in range(max_turns):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            system=system,
            tools=tools,
            messages=messages,
        )

        # Append assistant turn to history
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            # Model is done — extract the last text block
            for block in reversed(response.content):
                if block.type == "text":
                    return block.text
            return ""

        if response.stop_reason == "max_tokens":
            # Context window exhausted mid-response — not safe to continue silently
            raise RuntimeError("Hit max_tokens; truncated response. Trim context and retry.")

        if response.stop_reason == "tool_use":
            tool_results = []
            for block in response.content:
                if block.type != "tool_use":
                    continue
                fn = dispatch.get(block.name)
                if fn is None:
                    result = f"Unknown tool: {block.name}"
                    is_error = True
                else:
                    try:
                        result = str(fn(**block.input))
                        is_error = False
                    except Exception as exc:
                        result = str(exc)
                        is_error = True
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                    "is_error": is_error,
                })
            # Append tool results as a user turn
            messages.append({"role": "user", "content": tool_results})

    raise RuntimeError(f"Agent did not complete within {max_turns} turns")

def handle_tool_use_turn(
    content: list,
    dispatch: dict[str, Any],
) -> list[dict]:
    """Execute all tool calls in a turn and return a list of tool_result blocks."""
    tool_results = []
    for block in content:
        if block.type != "tool_use":
            continue  # skip text blocks if any
        fn = dispatch.get(block.name)
        if fn is None:
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": f"No handler registered for tool '{block.name}'",
                "is_error": True,
            })
            continue
        try:
            output = fn(**block.input)
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": str(output),
                "is_error": False,
            })
        except Exception as exc:
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": f"Error: {exc}",
                "is_error": True,
            })
    return tool_results

# Multiple tools can also be dispatched in parallel
import concurrent.futures

def handle_tool_use_turn_parallel(
    content: list,
    dispatch: dict[str, Any],
    max_workers: int = 4,
) -> list[dict]:
    tool_use_blocks = [b for b in content if b.type == "tool_use"]

    def run_one(block):
        fn = dispatch.get(block.name)
        if fn is None:
            return {"type": "tool_result", "tool_use_id": block.id,
                    "content": f"Unknown tool: {block.name}", "is_error": True}
        try:
            return {"type": "tool_result", "tool_use_id": block.id,
                    "content": str(fn(**block.input)), "is_error": False}
        except Exception as exc:
            return {"type": "tool_result", "tool_use_id": block.id,
                    "content": str(exc), "is_error": True}

    with concurrent.futures.ThreadPoolExecutor(max_workers=max_workers) as pool:
        results = list(pool.map(run_one, tool_use_blocks))
    return results

from collections import Counter

class LoopGuard:
    def __init__(self, max_turns: int = 20, max_identical: int = 3):
        self.max_turns = max_turns
        self.max_identical = max_identical
        self._turns = 0
        self._call_counts: Counter = Counter()

    def check_turn(self) -> None:
        self._turns += 1
        if self._turns > self.max_turns:
            raise RuntimeError(
                f"Agent exceeded {self.max_turns} turns. "
                "Possible infinite loop — check tool error handling."
            )

    def check_tool_calls(self, tool_results: list[dict]) -> None:
        for result in tool_results:
            # Use tool_use_id as a proxy for the call signature
            # In production, hash (name, input) for better detection
            key = result.get("tool_use_id", "")
            self._call_counts[key] += 1

    def check_repeated_errors(self, tool_results: list[dict]) -> None:
        error_names = [r.get("tool_use_id", "") for r in tool_results if r.get("is_error")]
        for name in error_names:
            if self._call_counts[name] >= self.max_identical:
                raise RuntimeError(
                    f"Tool '{name}' has failed {self._call_counts[name]} consecutive times. "
                    "Aborting to avoid loop."
                )

def build_initial_messages(
    task: str,
    prior_context: str | None = None,
) -> list[dict]:
    if prior_context:
        # Inject retrieved memory as the first user message,
        # then the actual task as continuation text.
        return [
            {
                "role": "user",
                "content": (
                    f"Background context from previous runs:\n{prior_context}\n\n"
                    f"Task: {task}"
                ),
            }
        ]
    return [{"role": "user", "content": task}]

# If you need the model to see context but NOT treat it as part of the task,
# use a multi-block user turn:
def build_initial_messages_multiblock(
    task: str,
    prior_context: str | None = None,
) -> list[dict]:
    content: list = []
    if prior_context:
        content.append({
            "type": "text",
            "text": f"Background context:\n{prior_context}",
        })
    content.append({"type": "text", "text": task})
    return [{"role": "user", "content": content}]

import anthropic

client = anthropic.Anthropic()

def run_agent_streaming(
    system: str,
    tools: list[dict],
    dispatch: dict,
    task: str,
    max_turns: int = 20,
) -> str:
    messages = [{"role": "user", "content": task}]

    for _ in range(max_turns):
        # Use the streaming context manager
        with client.messages.stream(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            system=system,
            tools=tools,
            messages=messages,
        ) as stream:
            # Surface text to caller in real time
            for text_chunk in stream.text_stream:
                print(text_chunk, end="", flush=True)

            # After streaming completes, get the full structured response
            response = stream.get_final_message()

        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            for block in reversed(response.content):
                if block.type == "text":
                    return block.text
            return ""

        if response.stop_reason == "max_tokens":
            raise RuntimeError("Truncated response — context too long.")

        # tool_use: dispatch and loop
        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue
            fn = dispatch.get(block.name)
            try:
                result = str(fn(**block.input)) if fn else f"Unknown: {block.name}"
                is_error = fn is None
            except Exception as exc:
                result, is_error = str(exc), True
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": result,
                "is_error": is_error,
            })
        messages.append({"role": "user", "content": tool_results})

    raise RuntimeError("Max turns exceeded")

from dataclasses import dataclass, field
from typing import Any

@dataclass
class FakeBlock:
    type: str
    text: str = ""
    id: str = ""
    name: str = ""
    input: dict = field(default_factory=dict)

@dataclass
class FakeResponse:
    content: list
    stop_reason: str

class FakeClient:
    """Replay a scripted sequence of responses for deterministic loop tests."""

    def __init__(self, script: list[FakeResponse]):
        self._script = iter(script)

    class messages:  # noqa: N801
        @staticmethod
        def create(**kwargs) -> FakeResponse:
            raise NotImplementedError  # replaced per-instance below

    def __init__(self, script):
        self._script = iter(script)
        self.messages = type(
            "M", (), {"create": lambda _self, **kw: next(self._script)}
        )()


def test_single_tool_call():
    script = [
        FakeResponse(
            content=[
                FakeBlock(type="tool_use", id="tu_1", name="echo", input={"msg": "hi"})
            ],
            stop_reason="tool_use",
        ),
        FakeResponse(
            content=[FakeBlock(type="text", text="Echo returned: hi")],
            stop_reason="end_turn",
        ),
    ]
    client = FakeClient(script)
    result = run_agent_with_client(
        client=client,
        system="You are a test agent.",
        tools=[],
        dispatch={"echo": lambda msg: msg},
        task="Echo hi.",
    )
    assert result == "Echo returned: hi"
